THE RISK:
{
 "id": "colo-follows-hyperscale-spec",
 "title": "Wholesale colocation inherits hyperscale rack-power specs — the 'safe' 18% slice buys what its tenants tell it to",
 "narrative": "The model treats colocation (seg.colocation, 0.18) as an independent PDU-buying segment — the sticky, PDU-friendly counterweight to hyperscale substitution risk. But CBRE reports that European colo take-up is being driven by hyperscalers and AI/HPC providers leasing wholesale capacity, and in wholesale deals the tenant specifies the rack-power architecture, not the landlord. If hyperscale tenants standardize on busway + power-shelf fit-outs in their leased suites, the substitution the boundary excluded walks through the colocation door: the colo slice's PDU content per MW falls in lockstep with hyperscale's, while the segment share in the model sits untouched — and seg.colocation carries no sensitivity band at all to absorb it.",
 "category": "boundary",
 "targetNodes": [
  "seg.colocation"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "CBRE reports European colocation take-up outstripping new supply, driven specifically by hyperscalers and AI/HPC providers — i.e., the marginal colo MW is a hyperscale-tenant MW, leased wholesale with tenant-specified fit-out",
   "refs": [
    "digest:seg-mix#c24",
    "digest:seg-mix#c15"
   ]
  },
  {
   "step": "propagation",
   "text": "Hyperscale tenants port their own rack-power standards (busway feeds, OCP-style in-rack shelves) into leased suites; colo landlords fit out to tenant spec, so the substitution path excluded at the boundary propagates into the colocation segment via the lease contract, not the landlord's preference",
   "refs": [
    "digest:seg-mix#c14",
    "ledger:seg.colocation"
   ]
  },
  {
   "step": "model-impact",
   "text": "seg.colocation's 0.18 rests on a single Synergy global capacity series (20–22% across vintages) with no sensitivityRange; the model has zero mechanism to register falling PDU content per colo MW, so the colocation slice is overstated in absolute PDU-euro terms during exactly the venture's entry window",
   "refs": [
    "ledger:seg.colocation",
    "digest:seg-mix#c1",
    "digest:seg-mix#c7"
   ]
  }
 ],
 "whyMissable": "Colocation is the segment founders point to as the hedge against hyperscale architecture risk — multi-tenant, heterogeneous, PDU-native. That framing assumes the landlord chooses the rack power. In wholesale colo (the part that is actually growing, per CBRE), the tenant chooses — and the tenant is the hyperscaler the hedge was supposed to protect against.",
 "expectedObviousness": "low",
 "falsifier": "Fit-out specifications or tenant BOMs from 2026 wholesale colo deals in Frankfurt/Amsterdam showing intelligent rack PDUs specified in hyperscale-leased suites at rates comparable to retail colo.",
 "likelihood": {
  "value": 0.34,
  "rationale": "CBRE documents hyperscale-driven colo absorption in Europe, and tenant-specified fit-out is standard in wholesale leases; but retail colocation and enterprise-tenant suites remain genuinely PDU-native, capping how much of the 0.18 converts within 12 months. [evidence revision: The trigger and propagation premises are well corroborated: CBRE confirms hyperscaler/AI-driven single-let wholesale take-up, and the Ardent Amsterdam suite is a concrete BYO-rack, busway-fed (no in-rack PDU) wholesale example in a target market. This modestly strengthens the original 0.3. The cap remains: retail colo and enterprise suites are genuinely PDU-native, and the 12-month conversion of the 0.18 slice is bounded — plus the model-structural claim (no sensitivity band) is unverifiable from external evidence. A small upward revision to 0.34 is warranted.]",
  "basis": "evidence",
  "revisedFrom": 0.3
 },
 "perturbation": [
  {
   "nodeId": "seg.colocation",
   "op": "set",
   "value": 0.12,
   "note": "Wholesale hyperscale-leased suites (~1/3 of the colo slice) adopt tenant busway/shelf specs; retail colo stays PDU-native"
  }
 ],
 "indicators": [
  {
   "signal": "Rack-power architecture named in wholesale colo fit-out specs and tenant technical requirements",
   "where": "TED (EU tenders electronic daily) and TenderNed for NL/DE data-center fit-out packages; Equinix and Digital Realty capex/earnings calls (xScale / hyperscale JV commentary)",
   "threshold": "≥2 CE wholesale deals where tenant spec mandates busway or shelf-based distribution in leased suites",
   "updates": "increases"
  },
  {
   "signal": "Colo landlords marketing 'OCP-ready' or shelf-compatible white space in CE",
   "where": "Dutch Data Center Association annual report; Frankfurt operator (e.g., NTT, CyrusOne, Vantage) product announcements and OCP Regional Summit EMEA talks",
   "threshold": "First CE colo operator advertising OCP-ready suites as standard product",
   "updates": "increases"
  },
  {
   "signal": "Retail vs wholesale mix in CE colo absorption",
   "where": "CBRE European Data Centres quarterly reports",
   "threshold": "Wholesale/hyperscale-leased share of CE take-up exceeding ~60%",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Interview 5 CE wholesale colo design/fit-out leads on who specifies rack power in leased suites and what share of 2026 pipeline is tenant-specified",
   "type": "information",
   "voiNodeId": "seg.colocation",
   "note": "Directly replaces the unbanded single-source 0.18 with a spec-controlled vs landlord-controlled split"
  },
  {
   "action": "Position the product for retail colo and enterprise-tenant suites first, with an explicit OCP-compatible roadmap (shelf-integrated metering module) to follow tenant specs rather than fight them",
   "type": "strategic",
   "voiNodeId": null,
   "note": "Converts the substitution wave into an adjacency rather than a foreclosure"
  }
 ],
 "evidenceStatus": "corroborated",
 "evidence": [
  {
